mapper.select:
SELECT * FROM search_index
WHERE entity_type = #{entityType}
  AND entity_id = #{entityId}

SELECT *
FROM search_index

    MATCH(title, description, tags) AGAINST(#{query} IN BOOLEAN MODE)

        AND FIND_IN_SET(entity_type, #{entityType}) > 0


        AND author_id = #{authorId}


        AND last_indexed_at >= #{dateFrom}


        AND last_indexed_at <= #{dateTo}


        AND tags LIKE CONCAT('%', #{status}, '%')



    ORDER BY last_indexed_at DESC
    ORDER BY title ASC
    ORDER BY MATCH(title, description, tags) AGAINST(#{query} IN BOOLEAN MODE) DESC

LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM search_index

    MATCH(title, description, tags) AGAINST(#{query} IN BOOLEAN MODE)

        AND FIND_IN_SET(entity_type, #{entityType}) > 0


        AND author_id = #{authorId}


        AND last_indexed_at >= #{dateFrom}


        AND last_indexed_at <= #{dateTo}


        AND tags LIKE CONCAT('%', #{status}, '%')

SELECT si.* FROM search_index si LEFT JOIN delivery_jobs dj ON si.entity_type = 'JOB' AND si.entity_id = dj.id
MATCH(si.title, si.description, si.tags) AGAINST(#{query} IN BOOLEAN MODE) AND FIND_IN_SET(si.entity_type, 'JOB,PROFILE') > 0 AND ( (si.entity_type = 'JOB' AND dj.courier_id = #{courierId}) OR (si.entity_type = 'PROFILE' AND si.author_id = #{courierId}) )
AND si.last_indexed_at >= #{dateFrom}
AND si.last_indexed_at <= #{dateTo}
AND si.tags LIKE CONCAT('%', #{status}, '%')
ORDER BY si.last_indexed_at DESC ORDER BY si.title ASC ORDER BY MATCH(si.title, si.description, si.tags) AGAINST(#{query} IN BOOLEAN MODE) DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM search_index si LEFT JOIN delivery_jobs dj ON si.entity_type = 'JOB' AND si.entity_id = dj.id
MATCH(si.title, si.description, si.tags) AGAINST(#{query} IN BOOLEAN MODE) AND FIND_IN_SET(si.entity_type, 'JOB,PROFILE') > 0 AND ( (si.entity_type = 'JOB' AND dj.courier_id = #{courierId}) OR (si.entity_type = 'PROFILE' AND si.author_id = #{courierId}) )
AND si.last_indexed_at >= #{dateFrom}
AND si.last_indexed_at <= #{dateTo}
AND si.tags LIKE CONCAT('%', #{status}, '%')

